mapper.select:


    l.is_deleted = #{isDeleted}
    and l.name = #{name}
    and l.cars like concat('%', #{cars}, '%')
    and l.shitype = #{shitype}
    and l.fulls = #{fulls}
    and l.bigs = #{bigs}
    and l.yiwu = #{yiwu}
    and l.company like concat('%', #{company}, '%')
    and l.create_time >= #{beginTime}
    and l.create_time <= #{endTime}

order by l.create_time desc, l.id desc
